const Q_ACCOUNTS_2020_MODEL_I=[{"id": "objective>Accounts>2020 Model I>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The advantages of double entry include all except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">To prepare final account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">For useful decision making</div>", "<div style=\"font-family:Cambria;font-size:17px;\">For suspense</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Helps to check arithmetical accuracy</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The merit of double entry are <br/> - To ensure complete record of each transaction <br/> - To prepare final account <br/> - Helps to check arithmetical accuracy <br/> - For useful decision making <br/> - Helps to ensure control of the business <br/> _ To show the financial positions</div>", "topic": "PRINCIPLE OF DOUBLE ENTRY : MEANING AND APPLICATION"}, {"id": "objective>Accounts>2020 Model I>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A document sent by the seller to the buyer to correct an overcharge is ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Receipts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Credit note</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Debit note</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Invoice</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A document sent by the seller to the buyer to correct an overcharge is a Credit Note. A credit note is a document sent by a seller to its buyer, or, in other words, a vendor to the customer, notifying that a credit has been provided to their account against the goods returned by the buyer.</div>", "topic": "SUBSIDIARY BOOKS : SOURCE DOCUMENT"}, {"id": "objective>Accounts>2020 Model I>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A book of original entry that is used to record transactions before they are posted to the ledgers is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sales day book</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Purchase day book</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cash book</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Journal</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Journal is used to record transactions before they are posted to the ledgers to purchase and sale of fixed assets on credit, correction of errors, opening of entries etc.</div>", "topic": "THE JOURNAL : MEANING AND USES OF JOURNAL"}, {"id": "objective>Accounts>2020 Model I>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Assets whose economic life exceeds one year is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Tangible assets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Current assets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fixed assets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Intangible assets</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fixed assets also known as non-current assets or long term assets are assets whose useful economic life exceeds one year.</div>", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION"}, {"id": "objective>Accounts>2020 Model I>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Payment of #60 for motor expenses entered in motor van account. What type of error occur?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Error of omission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Error of commission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Error of original entry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Error of principle</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Error of principle is a type of error whereby a transaction is entered in the wrong class of account.</div>", "topic": "CORRECTION OF ERRORS : ERRORS THAT DO NOT AFFECT THE AGREEMENT OF THE TRIAL BALANCE"}, {"id": "objective>Accounts>2020 Model I>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An account used to record differences in the trial balance temporarily until errors are detected is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Control account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cash book</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Suspense account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Trial balance</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Suspense account is an account used to record the differences in the trial balance temporarily until errors are detected.</div>", "topic": "SUSPENSE ACCOUNT : MEANING AND USES OF SUSPENSE ACCOUNT"}, {"id": "objective>Accounts>2020 Model I>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the following information to answer below questions  <br/>                                                                                             # <br/> Purchases                                                                       2,000 <br/> Opening stock                                                                   900 <br/> Closing stock                                                                     300 <br/> Sales                                                                               3,850 <br/>  <br/> Gross profit is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1,850</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1,250</div>", "<div style=\"font-family:Cambria;font-size:17px;\">950</div>", "<div style=\"font-family:Cambria;font-size:17px;\">650</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gross profit= sales- cost of goods sold(cost price) <br/>     Cost price= Opening stock+purchase-closing stock <br/>                          =900+2,000-300 <br/>                             = 2,600 <br/> Gross profit =     3,850-2,600 <br/>                          = 1,250</div>", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES"}, {"id": "objective>Accounts>2020 Model I>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the following information to answer below questions  <br/>                                                                                             # <br/> Purchases                                                                       2,000 <br/> Opening stock                                                                   900 <br/> Closing stock                                                                     300 <br/> Sales                                                                               3,850 <br/> The cost of goods available is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3,850</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2,900</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2,300</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2,000</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> Cost of goods available =Opening stock+purchase <br/>                                          =      900+2000 <br/>                                                    = 2,900 <br/> </div>", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES"}, {"id": "objective>Accounts>2020 Model I>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Rent prepaid by a business is shown in the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Trading account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Trial balance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Balance sheet</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cash book</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rent prepaid by a business is an asset and is shown in the balance sheet. It is an example of a prepaid expense, which is an asset because it provides future economic benefits to the business.</div>", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET"}, {"id": "objective>Accounts>2020 Model I>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Patent right and copy right are classified as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Intangible assets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fixed assets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Wasting assets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Current assets</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Patent right and copyright are examples of intangible assets. Intangible assets are non-physical assets that have a monetary value since they represent potential revenue. Intangible assets include patents, copyrights, trademarks, trade names, franchise licenses, government licenses, goodwill, and other items that are distinct and confer specific rights to their owners.</div>", "topic": "DEPRECIATION OF FIXED ASSETS : MEANING AND REASONS FOR CHARGING DEPRECIATION"}, {"id": "objective>Accounts>2020 Model I>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the following information to answer below questions: <br/> A company had an authorized share capital of #50,000. It offered applicants #30,000 share capital out of which the company collected #25,000. <br/>  <br/> What is the issued capital?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#20,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#30,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#25,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#5,000</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Issued capital is the capital issued out of the authorized/registered or nominal capital. #30,000 shares was issued out from #50,000 authorized capital. <br/> Therefore, #30,000 is the issued capital.</div>", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES"}, {"id": "objective>Accounts>2020 Model I>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the following information to answer below questions: <br/> A company had an authorized share capital of #50,000. It offered applicants #30,000 share capital out of which the company collected #25,000.What was the paid-up capital?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#30,00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#10,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#25,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#5,000</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Paid up capital is a capital which has been subscribed for and fully paid for.The #25,000 that was collected by the company is the paid up capital.</div>", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES"}, {"id": "objective>Accounts>2020 Model I>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the following information to answer below questions: <br/> A company had an authorized share capital of #50,000. It offered applicants #30,000 share capital out of which the company collected #25,000.What was the unissued capital?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#5,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#50,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#30,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#20,000</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Unissued capital is a capital that has not been issued out from registered/authorized or nominal capital. <br/> Therefore, Unissued capital = Registered capital - Issued capital <br/>                                                  =      50,000 - 30,000 <br/>                                                         =  20,000 <br/> </div>", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES"}, {"id": "objective>Accounts>2020 Model I>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The dividend declared before the end of the year is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Final dividend</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Interim dividend</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ordinary dividend</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Preference dividend</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An interim dividend is a dividend payment made before a company's Annual General Meeting (AGM) and final financial statements. This dividend is usually decided by the company's board of directors.</div>", "topic": "COMPANY ACCOUNT : INTRODUCTION , TYPES AND KINDS OF COMPANIES"}, {"id": "objective>Accounts>2020 Model I>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the following information to answer questions below: <br/> Tade and Nkirun were in partnership sharing profit in the ratio 3:2.Their respective capitals were #4,000 and #2,000 and their drawings #1,800 and #1,200. Profit during the year was #5,400, before 5% interest on capital.No interest was chargeable on drawings. <br/>  <br/> What was Tade's share of profit for the year?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#2,040</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#3,060</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#3,240</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#1,800</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">5% interest on capital: <br/> Tade = 5% x  4000 = 200 <br/> Nkirun = 5% x 2000 =   100 <br/> Total ratio=  3+2 =5 <br/> Therefore, Tade's share of profit = Net profit - Interest on capital <br/>                                                          = 5,400 - (200+100) <br/>                                                          = 5,100 <br/>                                                          = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">3</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">5</span>  x   5100 = 3,060 <br/> </div>", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR"}, {"id": "objective>Accounts>2020 Model I>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> Use the following information to answer questions below: <br/> Tade and Nkirun were in partnership sharing profit in the ratio 3:2.Their respective capitals were #4,000 and #2,000 and their drawings #1,800 and #1,200. Profit during the year was #5,400, before 5% interest on capital.No interest was chargeable on drawings. What was the balance carried down on Nkirun account?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#3,060</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#940</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#2,040</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#1,460</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nkirun's share of profit=     2/5      x     5,100 <br/>                                                    <br/>                                              =  2,040 <br/>  Nkirun's current account balance =  interest on capital + share of profit - drawwings <br/>                                                                 = 100 + 2,040 - 1,200 <br/>                                                                        =     940</div>", "topic": "PARTNERSHIP ACCOUNT : ACCOUNTING ENTRIES AT THE END OF THE FINANCIAL YEAR"}, {"id": "objective>Accounts>2020 Model I>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Oshola social club <br/> Statement of account 2000 financial year 31/12/98 <br/>                                                                                 # <br/> Subscription in arrears    ------------------           21,000 <br/> Subscription in advance ------------------            12,000 <br/> Receipts during the year  -----------------                          2000  <br/> Arrears   2017    ------------------                         21,000 <br/> Dues      2018     ------------------                        48,000 <br/> Advance 2019     ------------------                        11,000 <br/>  <br/> The subscription transferable to the income and expenditure account is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#48,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#59,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#60,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#69,000</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">                                                               Subscription account <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">                                 </td><td style=\"border:1px solid black;text-align:center;\">                      #</td><td style=\"border:1px solid black;text-align:center;\">                                                                     </td><td style=\"border:1px solid black;text-align:center;\">        #</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Owing blf </td><td style=\"border:1px solid black;text-align:center;\">                                   21000 </td><td style=\"border:1px solid black;text-align:center;\">                                              Prepaid b/f  </td><td style=\"border:1px solid black;text-align:center;\">         12000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Income and expenditure </td><td style=\"border:1px solid black;text-align:center;\">           60000 </td><td style=\"border:1px solid black;text-align:center;\">                                              Cash (2017)</td><td style=\"border:1px solid black;text-align:center;\">         21000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">cash(2019)</td><td style=\"border:1px solid black;text-align:center;\">                                11000  </td><td style=\"border:1px solid black;text-align:center;\">                                             Cash (2018) </td><td style=\"border:1px solid black;text-align:center;\">        48000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">                          </td><td style=\"border:1px solid black;text-align:center;\">                                      </td><td style=\"border:1px solid black;text-align:center;\">                                             Cash (2019) </td><td style=\"border:1px solid black;text-align:center;\">       11000 </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">                                                  </td><td style=\"border:1px solid black;text-align:center;\"> 92000 </td><td style=\"border:1px solid black;text-align:center;\">           </td><td style=\"border:1px solid black;text-align:center;\">                                                                  92000</td></tr></table></div></div>", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS"}, {"id": "objective>Accounts>2020 Model I>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The receipt and payment account for a non-profit making organisation  is equivalent to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Profit and loss</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cash book</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Balance sheet</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Control account</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The receipt and payment account is a summary of the cash book. It is a statement of cash actually received and paid during a given period,receipts being debited and payments credited.</div>", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : RECEIPTS AND PAYMENTS ACCOUNTS"}, {"id": "objective>Accounts>2020 Model I>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The excess of income over expenditure is usually transferred to the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Trading account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Profit and loss account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Balance sheet</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Statement of Affairs</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The excess of income over expenditure is usually transferred to the balance sheet. If the income is greater than the expenditure ,it is called surplus and it is added to the accumulated fund and when the expenditure is greater than the income, it is subtracted from the accumulated fund from the balance sheet.</div>", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS"}, {"id": "objective>Accounts>2020 Model I>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is debited to the sales ledger control account?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Credit note issued to customer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Credit note received form supplier</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Debit note issued to customer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Debit note received from supplier</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Debit note issued to customer is debited to the sales ledger control account.</div>", "topic": "CONTROL ACCOUNTS : SALES LEDGER CONTROL ACCOUNT"}, {"id": "objective>Accounts>2020 Model I>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these will not appear in the control account</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Discount received</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bills receivable</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Trade discount</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Contra settlement</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A control account is a summary account in the general ledger. The detail that supports the summary account totals is maintained in a subsidiary ledger. 'Trade discount' is a reduction in the listed price of an item. It is not a transaction that affects the financial position of a company, hence it does not appear in the control account.</div>", "topic": "CONTROL ACCOUNTS : INTRODUCTION, ADVANTAGES OF CONTROL ACCOUNTS"}, {"id": "objective>Accounts>2020 Model I>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The uses of control includes all except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Location of error</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Prevention of fraud</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Saves time</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Determination of gross profit</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The uses of control account are: <br/> - location of error <br/> - aids management control <br/> - easy detection of missing figures <br/> - preparation of interim final account <br/> - saves time and grouping of accounts</div>", "topic": "CONTROL ACCOUNTS : INTRODUCTION, ADVANTAGES OF CONTROL ACCOUNTS"}, {"id": "objective>Accounts>2020 Model I>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the information to answer questions below: <br/>                                                                                           # <br/> Stock of Raw materials:  January 1st   -------------                      32,160 <br/>   ---------------------------      December 31st  -------------                29,640 <br/> Purchase of Raw materials--------------                                       145,600 <br/> Manufacturing wages-------------                                                  52,860 <br/> Factory insurance  ------------                                                       6,538 <br/> Direct expenses-------------                                                          12,500 <br/>  <br/> The cost of raw materials consumed is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#148,120</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#220,480</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#155,120</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#287,318</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cost of raw materials consumed = Opening stock of raw materials+Purchases of raw materials- Closing stock <br/>                                                           = 32,160+145,600-29,640 <br/>                                                            = 148,120</div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>2020 Model I>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> Use the information to answer questions below: <br/>                                                                                           # <br/> Stock of Raw materials:  January 1st   -------------                      32,160 <br/>   ---------------------------      December 31st  -------------                29,640 <br/> Purchase of Raw materials--------------                                       145,600 <br/> Manufacturing wages-------------                                                  52,860 <br/> Factory insurance  ------------                                                       6,538 <br/> Direct expenses-------------                                                          12,500 <br/> The prime cost is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#213,480</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#177,760</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#148,120</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#155,120</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Prime cost = cost of raw materials consumed+ Direct cost <br/>                     =  148,120+ (52,860+12,500) <br/>                        = 148,120+ 65,360 <br/>                           = 213,480 <br/> </div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>2020 Model I>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The elements of depreciation include all except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Original cost of asset</div>", "<div style=\"font-family:Cambria;font-size:17px;\">obsolescence</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Salvage value</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Estimated useful life</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Depreciation is the systematic allocation of the depreciable amount of an asset over its useful life. The elements of depreciation include the original cost of the asset, its salvage value, and its estimated useful life. Obsolescence is not an element of depreciation, but rather a cause of depreciation.</div>", "topic": "DEPRECIATION OF FIXED ASSETS : CAUSES AND ELEMENTS OF DEPRECIATION"}, {"id": "objective>Accounts>2020 Model I>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The fund set up for capital project and expenditure is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Contigency fund</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Consolidated fund</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Development fund</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Warranty fund</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Development fund was set up by the constitution purposely for capital project and expenditure.The fund is used to provide infrasturctural facilities.</div>", "topic": "PUBLIC SECTOR ACCOUNTING : PURPOSE AND DIFFERENCE BETWEEN GOVERNMENT AND COMMERCIAL ACCOUNTING"}, {"id": "objective>Accounts>2020 Model I>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Goods charged to the branches can be priced using these methods except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Profit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cost price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cost plus a percentage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Selling price</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Transfer of stock of goods to the branch can be charged to branches using any of these pricing method are: <br/> - cost price <br/> - cost plus a percentage <br/> - selling price</div>", "topic": "BRANCH ACCOUNTING : PRICING METHODS"}, {"id": "objective>Accounts>2020 Model I>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the following information to answer questions below <br/>  <br/> The sales departments are: <br/> A ---------------------                                            #20,000 <br/> B---------------------                                             #30,000 <br/> C---------------------                                             #40,000 <br/> Selling expenses---------------------                    #16,000 <br/> Insurance--------------------                                #25,000 <br/> Assuming the floor area are: A: <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">2</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">5</span>; B:<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">2</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">5</span>; C:<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">5</span> <br/>  <br/> What portion is apportion to departmental A using the sales basis? <br/>                   </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#5,333</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#7,111</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#3,556</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#90,000</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Total sales= 20,000+30,000+40,000= 90,000 <br/> Using the sales basis: <br/>  <br/> Dept A= <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">20,000</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">90,000</span> x 16,000  <br/>  <br/> = 3,556</div>", "topic": "DEPARTMENTAL ACCOUNT : METHODS OF APPORTIONMENT OF EXPENSES"}, {"id": "objective>Accounts>2020 Model I>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">  <br/> Use the following information to answer questions below <br/>  <br/> The sales departments are: <br/> A ---------------------                                            #20,000 <br/> B---------------------                                             #30,000 <br/> C---------------------                                             #40,000 <br/> Selling expenses---------------------                    #16,000 <br/> Insurance--------------------                                #25,000 <br/> Assuming the floor area are: A: <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">2</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">5</span>; B:<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">2</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">5</span>; C:<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">5</span> <br/>  <br/> What portion is apportion to departmental B using the floor area basis?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#10,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#15,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#5,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#20,000</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Using the floor area basis: Insurance <br/> Dept B = 2/5  x  25,000 <br/>                           <br/>                       =   10,000</div>", "topic": "DEPARTMENTAL ACCOUNT : METHODS OF APPORTIONMENT OF EXPENSES"}, {"id": "objective>Accounts>2020 Model I>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The accounting concept which states that financial performance of a company should be divided into accounting periods is known as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Accounting period concept</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fairness concept</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Conservatism concept</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dual aspect concept</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Accounting period concept is also known as Periodicity concept.This principle states that financial performance of a company should be divided into accounting periods,usually a year.</div>", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS"}, {"id": "objective>Accounts>2020 Model I>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the information below to answer the question <br/>                                                                               # <br/> Balance as per cash book ----------------              7,000 <br/> Unpresented cheques----------------                      3,000 <br/> Uncredited lodgements----------------                    1,650 <br/> Dividend received not entered in the cash book-----------  1,000 <br/> Bank charges ----------------                                   150 <br/> Standing order payments ----------------                 500 <br/>  <br/> Calculate the balance in the bank statement</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#6,300</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#5,300</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#700</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#8,700</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">                            </td><td style=\"border:1px solid black;text-align:center;\">                      # </td><td style=\"border:1px solid black;text-align:center;\">                              #</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Balance as per cash book</td><td style=\"border:1px solid black;text-align:center;\">               </td><td style=\"border:1px solid black;text-align:center;\">                      7000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Add: Unpresented cheque</td><td style=\"border:1px solid black;text-align:center;\">     3000</td><td style=\"border:1px solid black;text-align:center;\"></td></tr><tr><td style=\"border:1px solid black;text-align:center;\">        Dividend   </td><td style=\"border:1px solid black;text-align:center;\">                      1000     </td><td style=\"border:1px solid black;text-align:center;\">       4000 </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">                         </td><td style=\"border:1px solid black;text-align:center;\">                                               </td><td style=\"border:1px solid black;text-align:center;\">        11000</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Less: Uncredited cheque</td><td style=\"border:1px solid black;text-align:center;\">       1650</td><td style=\"border:1px solid black;text-align:center;\"></td></tr><tr><td style=\"border:1px solid black;text-align:center;\">          Standing order    </td><td style=\"border:1px solid black;text-align:center;\">             500</td><td style=\"border:1px solid black;text-align:center;\"></td></tr><tr><td style=\"border:1px solid black;text-align:center;\">          Bank charges     </td><td style=\"border:1px solid black;text-align:center;\">             150      </td><td style=\"border:1px solid black;text-align:center;\">    2300 </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Bank as per bank statement  </td><td style=\"border:1px solid black;text-align:center;\">                       </td><td style=\"border:1px solid black;text-align:center;\">          8700</td></tr></table></div></div>", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREENMENT BETWEEN CASH BOOK & BANK STATEMENT"}, {"id": "objective>Accounts>2020 Model I>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An auditor who is appointed by the management to examine and report on the works of the various sections is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">External auditor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Financial auditor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Management auditor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Internal auditor</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Internal auditor is an auditor who is appointed by the management to examine and report on the work of the various sections/departments in the organizations.</div>", "topic": "INTRODUCTION TO ACCOUNTING : USERS OF ACCOUNTING & ROLES OF ACCOUNTING"}, {"id": "objective>Accounts>2020 Model I>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the advantage of Fifo is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Overstate profit during inflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Administrative clumsy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">No unrealized profit or loss</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It is cumbersome</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The advantages of Fifo are: <br/> - Easy to understand and operate <br/> - No realized profit or loss <br/> - Closing stock is valued at current price <br/> - It is realistic <br/> - Helps to avoid deterioration and obsolescence</div>", "topic": "STOCK VALUATION : ADVANTAGES AND DISADVANTAGES OF EACH METHODS"}, {"id": "objective>Accounts>2020 Model I>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The similarities between joint venture and partnership include all except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">To make profit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Both maintain one account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Involves two or more people</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Both have rights and duties</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The similarities between joint venture and partnership are: <br/> - Aims is profit making <br/> - Both involve two or more people <br/> - Both have rights and duties <br/> - They share profits and losses according to agreement or equally</div>", "topic": "PARTNERSHIP ACCOUNT : INTRODUCTION AND TYPES OF PARTNERS( PARTNERSHIP)"}, {"id": "objective>Accounts>2020 Model I>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When shares are fully paid it becomes</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Stock</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Debenture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bonds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dividend</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Stock is the collection of shares or bundle  of shares.When shares are fully paid,it is converted into stock.</div>", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES"}, {"id": "objective>Accounts>2020 Model I>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the following to answer the question <br/>                                                Cash book <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">  Dr      </td><td style=\"border:1px solid black;text-align:center;\">#</td><td style=\"border:1px solid black;text-align:center;\">          Cr         </td><td style=\"border:1px solid black;text-align:center;\"> #</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Capital</td><td style=\"border:1px solid black;text-align:center;\">6600</td><td style=\"border:1px solid black;text-align:center;\">Purchases</td><td style=\"border:1px solid black;text-align:center;\">3500</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Sales</td><td style=\"border:1px solid black;text-align:center;\">3000</td><td style=\"border:1px solid black;text-align:center;\">Stationery</td><td style=\"border:1px solid black;text-align:center;\">1300</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Debtors</td><td style=\"border:1px solid black;text-align:center;\">2500</td><td style=\"border:1px solid black;text-align:center;\">Wages</td><td style=\"border:1px solid black;text-align:center;\">2700</td></tr></table></div> <br/>  <br/> The owner wishes to maintain amount equal to 1/3 of capital as drawings. <br/> The amount withdrawn is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#2,100</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#2,200</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#4,400</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#6,400</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Amount withdrawn= 1/3 x capital <br/>                                = 1/3 x 6,600 <br/>                                   = 2,200</div>", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK"}, {"id": "objective>Accounts>2020 Model I>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the following to answer the question <br/>                                                Cash book <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">  Dr      </td><td style=\"border:1px solid black;text-align:center;\">#</td><td style=\"border:1px solid black;text-align:center;\">          Cr         </td><td style=\"border:1px solid black;text-align:center;\"> #</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Capital</td><td style=\"border:1px solid black;text-align:center;\">6600</td><td style=\"border:1px solid black;text-align:center;\">Purchases</td><td style=\"border:1px solid black;text-align:center;\">3500</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Sales</td><td style=\"border:1px solid black;text-align:center;\">3000</td><td style=\"border:1px solid black;text-align:center;\">Stationery</td><td style=\"border:1px solid black;text-align:center;\">1300</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Debtors</td><td style=\"border:1px solid black;text-align:center;\">2500</td><td style=\"border:1px solid black;text-align:center;\">Wages</td><td style=\"border:1px solid black;text-align:center;\">2700</td></tr></table></div> <br/> The cash book closing balance will be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#900</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#2,400</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#4,200</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#4,600</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Compare the total of the debit side and the credit and find the difference <br/> Debit side = 6,600+3,000+2,500 <br/>                       = 12,100 <br/> Credit side= 3,500+1,300+2,700 <br/>                          = 7,500 <br/> Since the debit side is greater than the credit side, we have <br/>                        = 12,100 - 7,500 <br/>                              = 4,600</div>", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK"}, {"id": "objective>Accounts>2020 Model I>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The cost price of a book is #9,000 and the selling price is #12,000. The mark up is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">66%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">33 <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">3</span>%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25%</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">Mark-up</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Profit<hr size=\"1\" />Cost price</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">100%</td><td style=\"text-align:center;\"></td></tr></table></div> <br/>   Profit = Selling price - cost price <br/>               = 12,000 - 9,000 <br/>                 = 3,000 <br/> Therefore,  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">Mark-up</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3000<hr size=\"1\" />9000</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">100%</td><td style=\"text-align:center;\"></td></tr></table></div> <br/>  <br/>                  =    33.3% or 33 1/3%</div>", "topic": "ACCOUNTING RATIO ( 1) : MARK UP AND MARGIN"}, {"id": "objective>Accounts>2020 Model I>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following errors would not be revealed by a trial balance?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Errors of omission</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Errors of commission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Errors of principle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">All of the above</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Errors of omission occur when a transaction is completely left out of the accounts, meaning it won't be reflected in the trial balance. Errors of commission and errors of principle may still be reflected in the trial balance but recorded incorrectly. </div>", "topic": "TRIAL BALANCE : ERRORS NOT DISCLOSED BY TRIAL BALANCE"}, {"id": "objective>Accounts>2020 Model I>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The trial balance will not disclose which of the following errors?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Posting an amount to the wrong account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Double posting of a transaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Not recording a transaction at all</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Miscalculating the total of the trial balance</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Not recording a transaction at all is an error of omission, which means it will not appear in the trial balance. The other options involve errors that would still be reflected in the trial balance, even if they are incorrect. </div>", "topic": "TRIAL BALANCE : ERRORS NOT DISCLOSED BY TRIAL BALANCE"}];
